+func expectedExportYAML(in, namespace string) (string, error) {
+	var doc map[interface{}]interface{}
+	if err := yaml.Unmarshal([]byte(stripYAMLComments(in)), &doc); err != nil {
+		return "", fmt.Errorf("unmarshalling expected yaml: %w", err)
+	}
+
+	if _, ok := doc["version"]; !ok {
+		doc["version"] = ext.DocumentVersion
+	}
+
+	if _, ok := doc["namespace"]; !ok {
+		if namespace == "" {
+			namespace = ext.DefaultNamespace
+		}
+
+		doc["namespace"] = namespace
+	}
+
+	return marshalNormalizedYAML(doc)
+}
+
+func normalizedYAML(in string) (string, error) {
+	var doc interface{}
+	if err := yaml.Unmarshal([]byte(stripYAMLComments(in)), &doc); err != nil {
+		return "", fmt.Errorf("unmarshalling generated yaml: %w", err)
+	}
+
+	return marshalNormalizedYAML(doc)
+}
+
+func marshalNormalizedYAML(doc interface{}) (string, error) {
+	out, err := json.MarshalIndent(normalizeYAML(doc), "", "  ")
+	if err != nil {
+		return "", fmt.Errorf("normalizing yaml: %w", err)
+	}
+
+	return string(out), nil
+}
+
+func normalizeYAML(in interface{}) interface{} {
+	switch v := in.(type) {
+	case map[interface{}]interface{}:
+		out := make(map[string]interface{}, len(v))
+		for key, value := range v {
+			out[fmt.Sprint(key)] = normalizeYAML(value)
+		}
+		return out
+	case []interface{}:
+		out := make([]interface{}, 0, len(v))
+		for _, value := range v {
+			out = append(out, normalizeYAML(value))
+		}
+		return out
+	default:
+		return v
+	}
+}
+
+func stripYAMLComments(in string) string {
+	var out strings.Builder
+
+	for _, line := range strings.Split(in, "\n") {
+		if strings.HasPrefix(strings.TrimSpace(line), "#") {
+			continue
+		}
+
+		out.WriteString(line)
+		out.WriteByte('\n')
+	}
+
+	return out.String()
+}
+
+func diffLines(expected, generated string) string {
+	expectedLines := strings.Split(expected, "\n")
+	generatedLines := strings.Split(generated, "\n")
+	maxLines := len(expectedLines)
+	if len(generatedLines) > maxLines {
+		maxLines = len(generatedLines)
+	}
+
+	var diff strings.Builder
+	for i := 0; i < maxLines; i++ {
+		var expectedLine, generatedLine string
+		if i < len(expectedLines) {
+			expectedLine = expectedLines[i]
+		}
+		if i < len(generatedLines) {
+			generatedLine = generatedLines[i]
+		}
+		if expectedLine == generatedLine {
+			continue
+		}
+
+		fmt.Fprintf(&diff, "@@ line %d @@\n- %s\n+ %s\n", i+1, expectedLine, generatedLine)
+	}
+
+	return diff.String()
+}
